# ---------- Helpers ----------
def _money(value: Decimal) -> Decimal:
    return value.quantize(Decimal("0.01"), rounding=ROUND_HALF_UP)

# ---------- Step 1: Validate Cart Items ----------
def validate_cart_items(cart_items: List[CartItem]) -> Decimal:
    if not cart_items:
        raise ValidationError("Cart is empty.")
    subtotal = Decimal("0")
    for item in cart_items:
        if item.quantity <= 0:
            raise ValidationError(f"Invalid quantity for product {item.product_id}.")
        product = PRODUCT_CATALOG.get(item.product_id)
        if not product:
            raise ValidationError(f"Product {item.product_id} not found.")
        if item.quantity > product.stock:
            raise ValidationError(f"Insufficient stock for product {product.name}.")
        subtotal += product.price * item.quantity
    return _money(subtotal)

# ---------- Step 2: Apply Discount Code ----------
def apply_discount(subtotal: Decimal, code_str: Optional[str], user: User) -> Decimal:
    if not code_str:
        return Decimal("0")
    code = DISCOUNT_CODES.get(code_str.upper())
    if not code:
        raise ValidationError("Invalid discount code.")
    if code.expires_at and datetime.utcnow() > code.expires_at:
        raise ValidationError("Discount code has expired.")
    if code.admin_only and not user.is_admin:
        raise ValidationError("Discount code restricted to admins.")
    if code.allowed_tiers and user.tier not in code.allowed_tiers:
        raise ValidationError("User tier not eligible for this discount code.")
    if code.fixed_amount_off is not None:
        discount = code.fixed_amount_off
    else:
        discount = subtotal * (code.percent_off / Decimal("100"))
    discount = min(discount, subtotal)  # discount cannot exceed subtotal
    return _money(discount)

# ---------- Step 3: Calculate Tax ----------
def calculate_tax(amount: Decimal, tax_rate: Decimal = Decimal("0.07")) -> Decimal:
    return _money(amount * tax_rate)

# ---------- Step 4: Process Payment ----------
def process_payment(user: User, amount: Decimal, payment_info: PaymentInfo) -> PaymentResult:
    # Stub implementation: 95% success rate
    if random.random() < 0.95:
        txn_id = str(uuid.uuid4())
        return PaymentResult(txn_id, True, "Payment processed successfully.")
    raise PaymentError("Payment declined by issuer.")

# ---------- Step 5: Create Order Record ----------
def create_order_record(user: User, cart_items: List[CartItem], subtotal: Decimal,
                        discount: Decimal, tax: Decimal, total: Decimal,
                        payment_txn: str) -> Order:
    order_id = str(uuid.uuid4())
    order = Order(order_id, user.user_id, cart_items, subtotal, discount, tax, total, payment_txn)
    ORDER_DB[order_id] = order
    # Deduct stock
    for item in cart_items:
        PRODUCT_CATALOG[item.product_id].stock -= item.quantity
    return order

# ---------- Orchestrator ----------
def checkout(user: User, cart_items: List[CartItem], payment_info: PaymentInfo,
             discount_code: Optional[str] = None, tax_rate: Decimal = Decimal("0.07")) -> Order:
    subtotal = validate_cart_items(cart_items)
    discount = apply_discount(subtotal, discount_code, user)
    taxable_amount = subtotal - discount
    tax = calculate_tax(taxable_amount, tax_rate)
    total = _money(taxable_amount + tax)
    payment_result = process_payment(user, total, payment_info)
    if not payment_result.success:
        raise PaymentError(payment_result.message)
    order = create_order_record(user, cart_items, subtotal, discount, tax, total, payment_result.transaction_id)
    return order

